<!DOCTYPE html>\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>User Management</title>\n</head>\n<body>\n    <h1>User Management</h1>\n    <table border="1">\n        <thead>\n            <tr>\n                <th>ID</th>\n                <th>Name</th>\n                <th>Email</th>\n                <th>Status</th>\n                <th>Actions</th>\n            </tr>\n        </thead>\n        <tbody>\n            <!-- Example User Row -->\n            <tr>\n                <td>1</td>\n                <td>John Doe</td>\n                <td>john@example.com</td>\n                <td>Active</td>\n                <td>\n                    <button onclick="blockUser(1)">Block</button>\n                    <button onclick="unblockUser(1)">Unblock</button>\n                </td>\n            </tr>\n            <!-- Add more user rows dynamically here -->\n        </tbody>\n    </table>\n    <script>\n        function blockUser(userId) {\n            // Implement block user logic here\n            alert('User ' + userId + ' blocked!');\n        }\n        function unblockUser(userId) {\n            // Implement unblock user logic here\n            alert('User ' + userId + ' unblocked!');\n        }\n    </script>\n</body>\n</html>